func solve(grid [][]int64, k int64) int64 {
    const INF int64 = 1 << 60
    m := len(grid)
    n := len(grid[0])
    if m == 0 || n == 0 {
        return 0
    }

    var max_val int64 = 0
    for i := 0; i < m; i++ {
        for j := 0; j < n; j++ {
            if grid[i][j] > max_val {
                max_val = grid[i][j]
            }
        }
    }

    dp := make([][][]int64, m)
    for i := range dp {
        dp[i] = make([][]int64, n)
        for j := range dp[i] {
            dp[i][j] = make([]int64, k+1)
            for t := int64(0); t <= k; t++ {
                dp[i][j][t] = INF
            }
        }
    }

    dp[0][0][0] = 0

    for i := 0; i < m; i++ {
        for j := 0; j < n; j++ {
            if i == 0 && j == 0 {
                continue
            }
            var candidate1, candidate2 int64 = INF, INF
            if i > 0 {
                candidate1 = dp[i-1][j][0] + grid[i][j]
            }
            if j > 0 {
                candidate2 = dp[i][j-1][0] + grid[i][j]
            }
            if candidate1 < candidate2 {
                dp[i][j][0] = candidate1
            } else {
                dp[i][j][0] = candidate2
            }
        }
    }

    for tele_count := int64(1); tele_count <= k; tele_count++ {
        suf_min := make([]int64, max_val+2)
        for i := range suf_min {
            suf_min[i] = INF
        }
        suf_min[max_val+1] = INF

        for i := 0; i < m; i++ {
            for j := 0; j < n; j++ {
                val := grid[i][j]
                if dp[i][j][tele_count-1] < suf_min[val] {
                    suf_min[val] = dp[i][j][tele_count-1]
                }
            }
        }

        for v := max_val; v >= 0; v-- {
            if suf_min[v] > suf_min[v+1] {
                suf_min[v] = suf_min[v+1]
            }
        }

        for i := 0; i < m; i++ {
            for j := 0; j < n; j++ {
                v := grid[i][j]
                candidate_tele := suf_min[v]
                if candidate_tele < dp[i][j][tele_count] {
                    dp[i][j][tele_count] = candidate_tele
                }
            }
        }

        for i := 0; i < m; i++ {
            for j := 0; j < n; j++ {
                if i > 0 {
                    candidate := dp[i-1][j][tele_count] + grid[i][j]
                    if candidate < dp[i][j][tele_count] {
                        dp[i][j][tele_count] = candidate
                    }
                }
                if j > 0 {
                    candidate := dp[i][j-1][tele_count] + grid[i][j]
                    if candidate < dp[i][j][tele_count] {
                        dp[i][j][tele_count] = candidate
                    }
                }
            }
        }
    }

    ans := INF
    for tele_count := int64(0); tele_count <= k; tele_count++ {
        if dp[m-1][n-1][tele_count] < ans {
            ans = dp[m-1][n-1][tele_count]
        }
    }
    return ans
}
